DELETE /* @SQLID=SUB0601_01-01#Sql006 */
FROM
	TB_MED_USERS_PRIV A
WHERE
	A.USER_ID = #{req.loginId}

		AND A.BRANCH_ID = #{req.sbiSecurityCode}


		AND A.BROKER_ID = #{req.brokerCode}


		AND A.SUB_BROKER_ID = #{req.subBrokerId}


		AND A.EMPLOYEE_ID = #{req.employeeId}

	AND A.DELETE_FLG = '0'
